SELECT *
FROM interv_session
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'

    AND session_id = #{sessionId}


    AND user_id = #{userId}


    AND equipment_code LIKE CONCAT('%', #{equipmentCode}, '%')


    AND device_code LIKE CONCAT('%', #{deviceCode}, '%')


    AND exercise_type = #{exerciseType}


    AND stage = #{stage}


    AND session_time >= #{params.beginTime}


    AND session_time <= #{params.endTime}

ORDER BY session_time DESC, session_id DESC

SELECT *
FROM interv_session
WHERE session_id = #{sessionId}
  AND tenant_id = #{tenantId}
  AND del_flag = '0'

SELECT *
FROM xd_training_set
WHERE session_id = #{sessionId}
  AND tenant_id = #{tenantId}
  AND del_flag = '0'
ORDER BY set_no ASC, set_id ASC
